  var ov = document.getElementById('mobileOverlay');
  if(ov){ ov.addEventListener('click', function(){
    document.getElementById('infoPanel').classList.remove('open');
    document.getElementById('contactPanel').classList.remove('open');
    document.getElementById('btnInfo').classList.remove('active');
    document.getElementById('btnContact').classList.remove('active');
    ov.classList.remove('show'); document.body.style.overflow = '';
  }); }


  // Custom cursor
  var cur = document.getElementById('cursor');
  if(cur){
    document.addEventListener('mousemove', function(e){
      cur.style.left = e.clientX + 'px';
      cur.style.top = e.clientY + 'px';
    });
    document.querySelectorAll('a,button,.gi,.dv-bread,.sidebar-logo,.dv-sticky-back,.avatar-wrap').forEach(function(el){
      el.addEventListener('mouseenter', function(){ cur.classList.add('big'); });
      el.addEventListener('mouseleave', function(){ cur.classList.remove('big'); });
    });
  }

  // Detail sticky header
  var dvStickyEl = document.getElementById('dvSticky');
  var dvStickyScrollHandler = null;
  function initStickyHeader(title){
    document.getElementById('dvStickyTitle').textContent = title || '';
    if(dvStickyScrollHandler) window.removeEventListener('scroll', dvStickyScrollHandler);
    dvStickyScrollHandler = function(){
      if(dvStickyEl) dvStickyEl.classList.toggle('show', window.scrollY > 80);
    };
    window.addEventListener('scroll', dvStickyScrollHandler);
    if(dvStickyEl) dvStickyEl.classList.remove('show');
  }

  document.getElementById('btnInfo').addEventListener('click', toggleInfo);
document.getElementById('btnContact').addEventListener('click', toggleContact);
document.getElementById('btnSend').addEventListener('click', sendContact);


  // Hello bubble rotation
  var helloWords = ['hello 👋','안녕 👋','こんにちは 👋','Hallo 👋','Bonjour 👋','Ciao 👋','Hola 👋','你好 👋','Olá 👋','مرحبا 👋'];
  var helloIdx = 0;
  var helloTimer = null;
  var helloBubble = document.getElementById('helloBubble');
  var helloMeasurer = document.createElement('span');
  helloMeasurer.style.cssText = 'position:fixed;visibility:hidden;font-size:.75rem;font-weight:600;font-family:Pretendard,sans-serif;white-space:nowrap;pointer-events:none;';
  document.body.appendChild(helloMeasurer);
  function measureText(txt){ helloMeasurer.textContent=txt; return helloMeasurer.offsetWidth; }
  function startHelloRotation(){
    if(helloTimer) return;
    if(helloBubble){ helloBubble.style.width = measureText(helloWords[0]) + 'px'; }
    helloTimer = setInterval(function(){
      helloIdx = (helloIdx + 1) % helloWords.length;
      if(helloBubble){
        // bubble shrinks → morph to path1
        if(morphTo && _p1){ morphTo(_p1); }
        helloBubble.style.transition = 'transform .22s ease, opacity .2s ease';
        helloBubble.style.transform = 'scale(0)';
        helloBubble.style.opacity = '0';
        setTimeout(function(){
          helloBubble.textContent = helloWords[helloIdx];
          helloBubble.style.width = measureText(helloWords[helloIdx]) + 'px';
          // bubble expands → morph to path2
          if(morphTo && _p2){ morphTo(_p2); }
          helloBubble.style.transition = 'transform .35s cubic-bezier(.34,1.4,.64,1), opacity .2s ease';
          helloBubble.style.transform = 'scale(1)';
          helloBubble.style.opacity = '1';
        }, 180);
      }
    }, 2250);
  }
  var stopTimeoutId = null;
  function stopHelloRotation(){
    clearInterval(helloTimer); helloTimer=null;
    if(stopTimeoutId){ clearTimeout(stopTimeoutId); stopTimeoutId=null; }
    helloIdx=0;
    if(helloBubble){
      helloBubble.style.transition = 'transform .22s ease, opacity .2s ease';
      helloBubble.style.transform = 'scale(0)';
      helloBubble.style.opacity = '0';
      setTimeout(function(){
        helloBubble.textContent = helloWords[0];
        helloBubble.style.width = measureText(helloWords[0]) + 'px';
      }, 220);
    }
  }
